# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, jsonify, send_file, request, abort
from pathlib import Path
import mimetypes
from datetime import datetime

app = Flask(__name__)

# Configuration
UPLOAD_ROOT = os.path.abspath('./user_uploads')

# Ensure upload root exists
os.makedirs(UPLOAD_ROOT, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user"""
    user_root = os.path.join(UPLOAD_ROOT, str(user_id))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def get_safe_path(user_id, relative_path):
    """
    Construct and validate a safe path within user's directory.
    Prevents directory traversal attacks.
    """
    user_root = get_user_root(user_id)
    
    # Join and normalize the path
    full_path = os.path.normpath(os.path.join(user_root, relative_path))
    
    # Ensure the path is within user's root directory
    if not full_path.startswith(user_root):
        abort(403, description="Access denied: Path outside user directory")
    
    return full_path


def get_file_info_dict(file_path):
    """Get detailed information about a file or directory"""
    stat_info = os.stat(file_path)
    is_dir = os.path.isdir(file_path)
    
    info = {
        'name': os.path.basename(file_path),
        'path': file_path,
        'type': 'directory' if is_dir else 'file',
        'size': stat_info.st_size if not is_dir else None,
        'created': datetime.fromtimestamp(stat_info.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat_info.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat_info.st_atime).isoformat(),
    }
    
    if not is_dir:
        mime_type, _ = mimetypes.guess_type(file_path)
        info['mime_type'] = mime_type or 'application/octet-stream'
        info['extension'] = os.path.splitext(file_path)[1]
    
    return info


@app.route('/api/files/<int:user_id>/list', methods=['GET'])
def list_directory(user_id):
    """
    List contents of a directory.
    Query parameter: path (relative path, defaults to root)
    """
    relative_path = request.args.get('path', '')
    
    try:
        full_path = get_safe_path(user_id, relative_path)
        
        if not os.path.exists(full_path):
            return jsonify({'error': 'Path does not exist'}), 404
        
        if not os.path.isdir(full_path):
            return jsonify({'error': 'Path is not a directory'}), 400
        
        items = []
        for item_name in os.listdir(full_path):
            item_path = os.path.join(full_path, item_name)
            try:
                item_info = {
                    'name': item_name,
                    'type': 'directory' if os.path.isdir(item_path) else 'file',
                    'size': os.path.getsize(item_path) if os.path.isfile(item_path) else None,
                    'modified': datetime.fromtimestamp(os.path.getmtime(item_path)).isoformat()
                }
                items.append(item_info)
            except (OSError, PermissionError):
                continue
        
        # Sort: directories first, then files, alphabetically
        items.sort(key=lambda x: (x['type'] != 'directory', x['name'].lower()))
        
        return jsonify({
            'path': relative_path or '/',
            'items': items,
            'count': len(items)
        })
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/files/<int:user_id>/download', methods=['GET'])
def download_file(user_id):
    """
    Download a file.
    Query parameter: path (relative path to file)
    """
    relative_path = request.args.get('path', '')
    
    if not relative_path:
        return jsonify({'error': 'Path parameter is required'}), 400
    
    try:
        full_path = get_safe_path(user_id, relative_path)
        
        if not os.path.exists(full_path):
            return jsonify({'error': 'File does not exist'}), 404
        
        if not os.path.isfile(full_path):
            return jsonify({'error': 'Path is not a file'}), 400
        
        return send_file(
            full_path,
            as_attachment=True,
            download_name=os.path.basename(full_path)
        )
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/files/<int:user_id>/info', methods=['GET'])
def get_file_info(user_id):
    """
    Get detailed information about a file or directory.
    Query parameter: path (relative path)
    """
    relative_path = request.args.get('path', '')
    
    try:
        full_path = get_safe_path(user_id, relative_path)
        
        if not os.path.exists(full_path):
            return jsonify({'error': 'Path does not exist'}), 404
        
        info = get_file_info_dict(full_path)
        
        # Add relative path to response
        user_root = get_user_root(user_id)
        info['relative_path'] = os.path.relpath(full_path, user_root)
        
        # If directory, add item count
        if os.path.isdir(full_path):
            try:
                info['item_count'] = len(os.listdir(full_path))
            except PermissionError:
                info['item_count'] = None
        
        return jsonify(info)
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/files/<int:user_id>/upload', methods=['POST'])
def upload_file(user_id):
    """
    Upload a file to a directory.
    Form data: file (file to upload), path (destination directory, optional)
    """
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    relative_path = request.form.get('path', '')
    
    try:
        destination_dir = get_safe_path(user_id, relative_path)
        
        # Create directory if it doesn't exist
        os.makedirs(destination_dir, exist_ok=True)
        
        # Sanitize filename
        filename = os.path.basename(file.filename)
        file_path = os.path.join(destination_dir, filename)
        
        # Save file
        file.save(file_path)
        
        return jsonify({
            'message': 'File uploaded successfully',
            'filename': filename,
            'path': os.path.relpath(file_path, get_user_root(user_id))
        }), 201
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/files/<int:user_id>/create_directory', methods=['POST'])
def create_directory(user_id):
    """
    Create a new directory.
    JSON body: path (relative path of new directory)
    """
    data = request.get_json()
    
    if not data or 'path' not in data:
        return jsonify({'error': 'Path is required'}), 400
    
    relative_path = data['path']
    
    try:
        full_path = get_safe_path(user_id, relative_path)
        
        if os.path.exists(full_path):
            return jsonify({'error': 'Path already exists'}), 400
        
        os.makedirs(full_path, exist_ok=True)
        
        return jsonify({
            'message': 'Directory created successfully',
            'path': relative_path
        }), 201
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.errorhandler(403)
def forbidden(e):
    return jsonify({'error': str(e.description)}), 403


@app.errorhandler(404)
def not_found(e):
    return jsonify({'error': 'Resource not found'}), 404


if __name__ == '__main__':
    app.run(debug=True, port=5000)